mapper.delete:
WITH RECURSIVE groups_to_delete AS ( -- 起始节点：要删除的父文件夹 SELECT id, parent_group_id FROM note_group WHERE id = #{groupId}
UNION ALL
-- 递归查找所有子文件夹 SELECT ng.id, ng.parent_group_id FROM note_group ng INNER JOIN groups_to_delete gtd ON ng.parent_group_id = gtd.id ) DELETE FROM note_group WHERE id IN (SELECT id FROM groups_to_delete)

mapper.select:
WITH RECURSIVE groups_to_delete AS ( -- 起始节点：要删除的父文件夹 SELECT id, parent_group_id FROM note_group WHERE id = #{groupId}
UNION ALL
-- 递归查找所有子文件夹 SELECT ng.id, ng.parent_group_id FROM note_group ng INNER JOIN groups_to_delete gtd ON ng.parent_group_id = gtd.id ) SELECT id FROM groups_to_delete
